+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
?/g, '\
');
+}
+
+function isInternal(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']): boolean {
+  return (mode === 'node' || mode === 'node_and_superjson') && line.includes('node:internal') ||
+    (mode === 'superjson' || mode === 'node_and_superjson') && /src\\/(?:transformer|plainer|index)\\.ts/.test(line);
+}
+
+function redact(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
+  if (mode === 'strip_cwd') {
+    const cwd = typeof process !== 'undefined' ? process.cwd().replace(/\\\\/g, '/') : '';
+    return cwd ? line.replaceAll(cwd, '') : line;
+  }
+  if (mode === 'basename') {
+    return line.replace(/(?:[A-Za-z]:)?(?:\\/|\\\\)(?:[^\\s():]+[\\\\/])*([^\\s/\\\\():]+)(?=[:)\\s]|$)/g, '$1');
+  }
+  return line;
+}
+
+function lines(stack: string, options: NormalizedErrorStackOptions, framesOrder: boolean): string[] {
+  const input = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
+  let result = input.split('\
');
+  if (options.trimLeadingWhitespace) result = result.map((line, index) => index ? line.replace(/^\\s+/, '') : line);
+  if (framesOrder) result = result.filter((line, index) => index === 0 || !isInternal(line, options.stripInternalFrames));
+  result = result.map(line => redact(line, options.redactPaths));
+  if (!framesOrder) result = result.slice(0, options.maxStackLines).filter((line, index) => index === 0 || !isInternal(line, options.stripInternalFrames));
+  else result = result.slice(0, options.maxStackLines);
+  return result;
+}
+
+export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
+  return lines(stack, options, false).join('\
');
+}
+
+export function processStackFrames(stack: string, options: NormalizedErrorStackOptions): Array<{ raw: string }> {
+  return lines(stack, options, true).map(raw => ({ raw }));
+}
