+function stackClassMatches(error: Error, superJson: SuperJSON): boolean {
+  const options = superJson.errorStackOptions;
+  return !!options && (options.classFilter.length === 0 || options.classFilter.includes(error.name));
+}
+
+function usesStackMode(error: Error, superJson: SuperJSON, mode: 'string' | 'frames'): boolean {
+  return superJson.errorStackOptions?.mode === mode && stackClassMatches(error, superJson);
+}
+
+function copyCause(error: Error, superJson: SuperJSON, depth: number, seen: Set<Error>): any {
+  const options = superJson.errorStackOptions!;
+  if (!isError((error as any).cause) || seen.has((error as any).cause)) return undefined;
+  if (options.includeCauses === 'none' || (options.includeCauses === 'direct' && depth > 0) || (options.includeCauses === 'deep' && depth >= options.maxCauseDepth)) return undefined;
+  const cause = (error as any).cause as Error;
+  const nextSeen = new Set(seen);
+  nextSeen.add(cause);
+  const plain: any = { name: cause.name, message: cause.message };
+  if (options.sanitizeMessage && stackClassMatches(cause, superJson)) plain.message = sanitizeMessage(plain.message);
+  const nested = copyCause(cause, superJson, depth + 1, nextSeen);
+  if (nested !== undefined) plain.cause = nested;
+  if (cause.name === 'AggregateError' && 'errors' in cause) plain.errors = (cause as any).errors;
+  const processor = superJson.errorClassRegistry.getProcessor(cause.name);
+  return processor ? processor(plain) : plain;
