+
+function serializeError(error: Error, superJson: SuperJSON, mode: 'off' | 'string' | 'frames'): any {
+  const options = superJson.errorStackOptions;
+  const configured = !!options;
+  const matches = stackClassMatches(error, superJson);
+  const plain: any = { name: error.name, message: error.message };
+
+  if (!configured) {
+    if ('cause' in error) plain.cause = (error as any).cause;
+    superJson.allowedErrorProps.forEach(prop => { plain[prop] = (error as any)[prop]; });
+    return plain;
